css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at center, #1a0a2e 0%, #070b18 100%); font-family: -apple-system, BlinkMacSystemFont, sans-serif; }
.calc { width: 360px; border-radius: 40px; background: #1c1c2e; box-shadow: 0 40px 80px rgba(0,0,0,0.6), 0 0 0 1px rgba(255,255,255,0.08); overflow: hidden; }
.calc-display { padding: 32px 28px 20px; text-align: right; min-height: 140px; display: flex; flex-direction: column; justify-content: flex-end; }
.calc-expr { font-size: 18px; color: rgba(255,255,255,0.35); margin-bottom: 8px; min-height: 24px; word-break: break-all; }
.calc-result { font-size: 56px; font-weight: 300; color: white; line-height: 1; word-break: break-all; }
.calc-keys { display: grid; grid-template-columns: repeat(4, 1fr); gap: 1px; background: rgba(255,255,255,0.05); }
.key { height: 90px; border: none; background: #2d2d42; color: white; font-size: 24px; font-weight: 400; cursor: pointer; transition: background 0.1s; user-select: none; } .key:active { background: rgba(255,255,255,0.2); }
.key.func { background: #3d3d52; color: #f97316; font-weight: 600; }
.key.op { background: #f97316; color: white; font-weight: 600; }
.key.op:active { background: #fb923c; }
.key.equal { background: linear-gradient(135deg, #f97316, #ea580c); }
.key.zero { grid-column: span 2; text-align: left; padding-left: 36px; }
.key:last-child { border-bottom-right-radius: 40px; } .key:nth-last-child(2) { border-bottom-left-radius: 40px; }

