let current = '0', prev = '', op = '', justCalc = false;
const res = document.getElementById('result');
const expr = document.getElementById('expr');
function update() { res.textContent = current; res.style.fontSize = current.length > 9 ? '32px' : current.length > 6 ? '42px' : '56px'; }
function num(n) {
  if (justCalc) { current = n; justCalc = false; }
  else { current = current === '0' ? n : current + n; }
  update();
}
function clearAll() { current = '0'; prev = ''; op = ''; expr.textContent = ''; update(); }
function setOp(o) {
  if (prev && op && !justCalc) calculate();
  prev = current; op = o;
  const symbols = { '+': '+', '-': '−', '*': '×', '/': '÷' };
  expr.textContent = current + ' ' + symbols[o];
  current = '0'; justCalc = false;
}
function calculate() {
  if (!op || !prev) return;
  const a = parseFloat(prev), b = parseFloat(current);
  let r;
  if (op === '+') r = a + b;
  else if (op === '-') r = a - b;
  else if (op === '*') r = a * b;
  else if (op === '/') r = b === 0 ? 'Hata' : a / b;
  expr.textContent = prev + ' ' + ({'+':'+','-':'−','*':'×','/':'÷'}[op]) + ' ' + current + ' =';
  current = r === 'Hata' ? 'Hata' : String(parseFloat(r.toFixed(10)));
  op = ''; justCalc = true; update();
}
function toggleSign() { if (current !== '0') { current = current.startsWith('-') ? current.slice(1) : '-' + current; update(); } }
function percent() { current = String(parseFloat(current) / 100); update(); }
function dot() { if (!current.includes('.')) { current += '.'; update(); } }
document.addEventListener('keydown', e => {
  if ('0123456789'.includes(e.key)) num(e.key);
  else if (e.key === '+') setOp('+');
  else if (e.key === '-') setOp('-');
  else if (e.key === '*') setOp('*');
  else if (e.key === '/') { e.preventDefault(); setOp('/'); }
  else if (e.key === 'Enter' || e.key === '=') calculate();
  else if (e.key === 'Escape') clearAll();
  else if (e.key === '.') dot();
  else if (e.key === 'Backspace') { current = current.length > 1 ? current.slice(0,-1) : '0'; update(); }
});
